25: // completionsResolver provides chat completions
26: type completionsResolver struct {
27: 	rl     completions.RateLimiter
28: 	db     database.DB
29: 	logger log.Logger
30: 	gp     gating.Provider
31: }
32: 
33: func NewCompletionsResolver(db database.DB, logger log.Logger, gp gating.Provider) graphqlbackend.CompletionsResolver {
34: 	rl := completions.NewRateLimiter(db, redispool.Store, gp, types.CompletionsFeatureChat)
35: 	return &completionsResolver{rl: rl, db: db, logger: logger, gp: gp}
36: }
37: 
38: func (c *completionsResolver) Completions(ctx context.Context, args graphqlbackend.CompletionsArgs) (_ string, err error) {
39: 	reasons, enabled := completionsapis.IsEnabled(ctx, c.logger, c.db, c.gp)
40: 	if !enabled {
41: 		trace.FromContext(ctx).SetAttributes(
42: 			attribute.StringSlice("disabled.reasons", reasons))
43: 		return "", errors.New("completions are not enabled")
44: 	}
45: 
46: 	// This GraphQL endpoint doesn't support picking the specific model, and just relies on the default
47: 	// Chat/FastChat model instead.
48: 	modelconfigSvc := modelconfig.Get()
49: 	modelConfig, err := modelconfigSvc.Get()
50: 	if err != nil {
51: 		return "", errors.Wrap(err, "getting current LLM configuration")
52: 	}
53: 
54: 	mref := modelConfig.DefaultModels.Chat
55: 	if args.Fast {
56: 		mref = modelConfig.DefaultModels.FastChat
57: 	}
58: 
59: 	provider, model, err := modelConfig.LookupModelConfigInfo(mref)
60: 	if err != nil {
61: 		return "", errors.Wrapf(err, "resolving mref %q", mref)
62: 	}
63: 	modelConfigInfo := types.ModelConfigInfo{Provider: provider, Model: model}
64: 
65: 	modelName := modelConfigInfo.Model.ModelName
66: 	ctx, done := completions.Trace(ctx, "resolver", modelName, int(args.Input.MaxTokensToSample)).
67: 		WithErrorP(&err).
68: 		Build()
69: 	defer done()
70: 
71: 	client, err := client.Get(ctx, c.logger, "completions.resolver", modelConfigInfo)
72: 	if err != nil {
73: 		return "", errors.Wrap(err, "GetCompletionStreamClient")
74: 	}
75: 
76: 	// Check rate limit.
77: 	if err := c.rl.TryAcquire(ctx); err != nil {
78: 		return "", err
79: 	}
80: 
81: 	params, err := convertArgs(args)
82: 	if err != nil {
83: 		return "", errors.Wrap(err, "convertArgs")
84: 	}
85: 	request := types.CompletionRequest{
86: 		Feature:         types.CompletionsFeatureChat,
87: 		ModelConfigInfo: modelConfigInfo,
88: 		Parameters:      params,
89: 		// GraphQL API is considered a legacy API.
90: 		Version: types.CompletionsVersionLegacy,
91: 	}
92: 	resp, err := client.Complete(ctx, c.logger, request)
93: 	if err != nil {
94: 		return "", errors.Wrap(err, "client.Complete")
95: 	}
96: 	return resp.Completion, nil
97: }
98: 
99: func convertArgs(args graphqlbackend.CompletionsArgs) (types.CompletionRequestParameters, error) {
100: 	messages, err := convertMessages(args.Input.Messages)
101: 	if err != nil {
102: 		return types.CompletionRequestParameters{}, err
103: 	}
104: 	return types.CompletionRequestParameters{
105: 		Messages:          messages,
106: 		Temperature:       float32(args.Input.Temperature),
107: 		MaxTokensToSample: int(args.Input.MaxTokensToSample),
108: 		TopK:              int(args.Input.TopK),
109: 		TopP:              float32(args.Input.TopP),
110: 	}, nil
111: }
112: 
113: func convertMessages(messages []graphqlbackend.Message) (result []types.Message, err error) {
114: 	for _, message := range messages {
115: 		role, err := types.NewMessageRole(strings.ToLower(message.Speaker))
116: 		if err != nil {
117: 			return nil, err
118: 		}
119: 		result = append(result, types.Message{
120: 			Role:    role,
121: 			Content: types.NewContentPartString(message.Text),
122: 		})
123: 	}
124: 	return result, nil
125: }
