3: import (
4: 	"context"
5: 	"fmt"
6: 	"time"
7: 
8: 	"github.com/sourcegraph/sourcegraph/internal/actor"
9: 	"github.com/sourcegraph/sourcegraph/internal/auth"
10: 	"github.com/sourcegraph/sourcegraph/internal/completions/types"
11: 	"github.com/sourcegraph/sourcegraph/internal/conf"
12: 	"github.com/sourcegraph/sourcegraph/internal/database"
13: 	"github.com/sourcegraph/sourcegraph/internal/gating"
14: 	"github.com/sourcegraph/sourcegraph/internal/keyvalue"
15: 	"github.com/sourcegraph/sourcegraph/internal/redispool"
16: 	"github.com/sourcegraph/sourcegraph/internal/requestclient"
17: 	"github.com/sourcegraph/sourcegraph/lib/errors"
18: )
19: 
20: type RateLimiter interface {
21: 	TryAcquire(ctx context.Context) error
22: }
23: 
24: // NewRateLimiter returns a request-count-based rate-limiter for completions requests.
25: func NewRateLimiter(
26: 	db database.DB,
27: 	rstore redispool.KeyValueStore,
28: 	gp gating.Provider,
29: 	scope types.CompletionsFeature,
30: ) RateLimiter {
31: 	return &rateLimiter{db: db, rstore: rstore, gp: gp, scope: scope}
32: }
33: 
34: type rateLimiter struct {
35: 	scope  types.CompletionsFeature
36: 	rstore redispool.KeyValueStore
37: 	db     database.DB
38: 	gp     gating.Provider
39: }
40: 
41: func (r *rateLimiter) TryAcquire(ctx context.Context) (err error) {
42: 	limit, err := getConfiguredLimit(ctx, r.db, r.gp, r.scope)
43: 	if err != nil {
44: 		return errors.Wrap(err, "failed to read configured rate limit")
45: 	}
46: 
47: 	if limit <= 0 {
48: 		// Rate limiting disabled.
49: 		return nil
50: 	}
51: 
52: 	// Check that the user is authenticated.
53: 	a := actor.FromContext(ctx)
54: 	if a.IsInternal() {
55: 		return nil
56: 	}
57: 	key := userKey(a.UID, r.scope)
58: 	if !a.IsAuthenticated() {
59: 		// Fall back to the IP address, if provided in context (ie. this is a request handler).
60: 		req := requestclient.FromContext(ctx)
61: 		var ip string
62: 		if req != nil {
63: 			ip = req.IP
64: 			// Note: ForwardedFor header in general can be spoofed. For
65: 			// Sourcegraph.com we use a trusted value for this so this is a
66: 			// reliable value to rate limit with.
67: 			if req.ForwardedFor != "" {
68: 				ip = req.ForwardedFor
69: 			}
70: 		}
71: 		if ip == "" {
72: 			return errors.Wrap(auth.ErrNotAuthenticated, "cannot claim rate limit for unauthenticated user without request context")
73: 		}
74: 		key = anonymousKey(ip, r.scope)
75: 	}
76: 
77: 	// Check the current usage. If
78: 	// no record exists, redis will return 0 and ErrNil.
79: 	currentUsage, err := r.rstore.Get(ctx, key).Int()
80: 	if err != nil && err != keyvalue.ErrNil {
81: 		return errors.Wrap(err, "failed to read rate limit counter")
82: 	}
83: 
84: 	// If the usage exceeds the maximum, we return an error. Consumers can check if
85: 	// the error is of type RateLimitExceededError and extract additional information
86: 	// like the limit and the time by when they should retry.
87: 	if currentUsage >= limit {
88: 		// Read TTL to compute the RetryAfter time.
89: 		ttl, err := r.rstore.TTL(ctx, key)
90: 		if err != nil {
91: 			return errors.Wrap(err, "failed to get TTL for rate limit counter")
92: 		}
93: 		return types.RateLimitExceededError{
94: 			Scope: r.scope,
95: 			Limit: limit,
96: 			// Return the minimum value of currentUsage and limit to not return
97: 			// confusing values when the limit was exceeded. This method increases
98: 			// on every check, even if the limit was reached.
99: 			Used:       min(currentUsage, limit),
100: 			RetryAfter: time.Now().Add(time.Duration(ttl) * time.Second),
101: 		}
102: 	}
103: 
104: 	// Now that we know that we want to let the user pass, let's increment the rate
105: 	// limit counter for the user.
106: 	// Note that the rate limiter _may_ allow slightly more requests than the configured
107: 	// limit, incrementing the rate limit counter and reading the usage futher up are currently
108: 	// not an atomic operation, because there is no good way to read the TTL in a transaction
109: 	// without a lua script.
110: 	// This approach could also slightly overcount the usage if redis requests after
111: 	// the INCR fail, but it will always recover safely.
112: 	// If Incr works but then everything else fails (eg ctx cancelled) the user spent
113: 	// a token without getting anything for it. This seems pretty rare and a fine trade-off
114: 	// since its just one token. The most likely reason this would happen is user cancelling
115: 	// the request and at that point its more likely to happen while the LLM is running than
116: 	// in this quick redis block.
117: 	// On the first request in the current time block, if the requests past Incr fail we don't
118: 	// yet have a deadline set. This means if the user comes back later we wouldn't of expired
119: 	// just one token. This seems fine. Note: this isn't an issue on subsequent requests in the
120: 	// same time block since the TTL would have been set.
121: 
122: 	if _, err := r.rstore.Incr(ctx, key); err != nil {
123: 		return errors.Wrap(err, "failed to increment rate limit counter")
124: 	}
125: 
126: 	// Set expiry on the key. If the key didn't exist prior to the previous INCR,
127: 	// it will set the expiry of the key to one day.
128: 	// If it did exist before, it should have an expiry set already, so the TTL >= 0
129: 	// makes sure that we don't overwrite it and restart the 1h bucket.
130: 	ttl, err := r.rstore.TTL(ctx, key)
131: 	if err != nil {
132: 		return errors.Wrap(err, "failed to get TTL for rate limit counter")
133: 	}
134: 	if ttl < 0 {
135: 		if err := r.rstore.Expire(ctx, key, int(24*time.Hour/time.Second)); err != nil {
136: 			return errors.Wrap(err, "failed to set expiry for rate limit counter")
137: 		}
138: 	}
139: 
140: 	return nil
141: }
142: 
143: func userKey(userID int32, scope types.CompletionsFeature) string {
144: 	return fmt.Sprintf("user:%d:%s_requests", userID, scope)
145: }
146: 
147: func anonymousKey(ip string, scope types.CompletionsFeature) string {
148: 	return fmt.Sprintf("anon:%s:%s_requests", ip, scope)
149: }
150: 
151: func getConfiguredLimit(ctx context.Context, db database.DB, gp gating.Provider, scope types.CompletionsFeature) (int, error) {
152: 	a := actor.FromContext(ctx)
153: 	if a.IsAuthenticated() && !a.IsInternal() {
154: 		var limit *int
155: 		var err error
156: 
157: 		// If an authenticated user exists, check if an override exists.
158: 		switch scope {
159: 		case types.CompletionsFeatureChat:
160: 			limit, err = db.Users().GetChatCompletionsQuota(ctx, a.UID)
161: 		case types.CompletionsFeatureCode:
162: 			limit, err = db.Users().GetCodeCompletionsQuota(ctx, a.UID)
163: 		default:
164: 			return 0, errors.Newf("unknown scope: %s", scope)
165: 		}
166: 		if err != nil {
167: 			return 0, err
168: 		}
169: 		if limit != nil {
170: 			return *limit, err
171: 		}
172: 	}
173: 
174: 	// Otherwise, fall back to the global limit.
175: 	cfg := conf.GetCompletionsConfig(conf.Get().SiteConfig(), gp)
176: 	switch scope {
177: 	case types.CompletionsFeatureChat:
178: 		if cfg != nil && cfg.PerUserDailyLimit > 0 {
179: 			return cfg.PerUserDailyLimit, nil
180: 		}
181: 	case types.CompletionsFeatureCode:
182: 		if cfg != nil && cfg.PerUserCodeCompletionsDailyLimit > 0 {
183: 			return cfg.PerUserCodeCompletionsDailyLimit, nil
184: 		}
185: 	default:
186: 		return 0, errors.Newf("unknown scope: %s", scope)
187: 	}
188: 
189: 	return 0, nil
190: }
