{"content":"1: package featurelimiter
2: 
3: import (
4: 	"context"
5: 	"encoding/json"
6: 	"net/http"
7: 	"strings"
8: 	"time"
9: 
10: 	"github.com/sourcegraph/log"
11: 
12: 	"github.com/sourcegraph/sourcegraph/cmd/cody-gateway/internal/actor"
13: 	"github.com/sourcegraph/sourcegraph/cmd/cody-gateway/internal/events"
14: 	"github.com/sourcegraph/sourcegraph/cmd/cody-gateway/internal/limiter"
15: 	"github.com/sourcegraph/sourcegraph/cmd/cody-gateway/internal/notify"
16: 	"github.com/sourcegraph/sourcegraph/cmd/cody-gateway/internal/response"
17: 	"github.com/sourcegraph/sourcegraph/internal/codygateway"
18: 	"github.com/sourcegraph/sourcegraph/internal/codygateway/codygatewayevents"
19: 	"github.com/sourcegraph/sourcegraph/internal/completions/types"
20: 	"github.com/sourcegraph/sourcegraph/internal/httpresponsewriter"
21: 	"github.com/sourcegraph/sourcegraph/internal/trace"
22: 	sgtrace "github.com/sourcegraph/sourcegraph/internal/trace"
23: 	"github.com/sourcegraph/sourcegraph/lib/errors"
24: )
25: 
26: type contextKey string
27: 
28: // ContextKeyFeature is the context key used to store the feature in the context
29: const ContextKeyFeature contextKey = "feature"
30: 
31: // WithFeature adds the feature to the context, using ContextKeyFeature.
32: // This is primarily used in tests to simulate the feature being extracted from a request.
33: func WithFeature(ctx context.Context, feature codygateway.Feature) context.Context {
34: 	return context.WithValue(ctx, ContextKeyFeature, feature)
35: }
36: 
37: // GetFeature gets the feature stored in the context using ContextKeyFeature.
38: //
39: // Handle() or HandleFeature() must have been called prior, or the context must contain
40: // a value for ContextKeyFeature, else an empty string will be returned.
41: func GetFeature(ctx context.Context) codygateway.Feature {
42: 	if f, ok := ctx.Value(ContextKeyFeature).(codygateway.Feature); ok {
43: 		return f
44: 	}
45: 	return ""
46: }
47: 
48: // Handle extracts features from codygateway.FeatureHeaderName and uses it to
49: // determine the appropriate per-feature rate limits applied for an actor. It
50: // only limits per-request.
51: func Handle(
52: 	baseLogger log.Logger,
53: 	eventLogger events.Logger,
54: 	cache limiter.RedisStore,
55: 	rateLimitNotifier notify.RateLimitNotifier,
56: 	next http.Handler,
57: ) http.Handler {
58: 	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
59: 		feature, err := ExtractFeature(r)
60: 		if err != nil {
61: 			response.JSONError(baseLogger, w, http.StatusBadRequest, err)
62: 			return
63: 		}
64: 
65: 		extractUsage := func(responseHeaders http.Header) (int, error) {
66: 			return 1, nil // per-request, so always consume 1 rate limit
67: 		}
68: 
69: 		HandleFeature(baseLogger, eventLogger, cache, rateLimitNotifier, feature, next, extractUsage).
70: 			ServeHTTP(w, r)
71: 	})
72: }
73: 
74: // ExtractFeature extracts the feature from the HTTP request headers.
75: func ExtractFeature(r *http.Request) (codygateway.Feature, error) {
76: 	h := strings.TrimSpace(r.Header.Get(codygateway.FeatureHeaderName))
77: 	if h == "" {
78: 		return "", errors.Newf("%s header is required", codygateway.FeatureHeaderName)
79: 	}
80: 	feature := types.CompletionsFeature(h)
81: 	if !feature.IsValid() {
82: 		return "", errors.Newf("invalid value for %s", codygateway.FeatureHeaderName)
83: 	}
84: 	// codygateway.Feature and types.CompletionsFeature map 1:1 for completions.
85: 	return codygateway.Feature(feature), nil
86: }
87: 
88: // HandleFeature uses a predefined feature to determine the appropriate per-feature
89: // rate limits applied for an actor.
90: func HandleFeature(
91: 	baseLogger log.Logger,
92: 	eventLogger events.Logger,
93: 	cache limiter.RedisStore,
94: 	rateLimitNotifier notify.RateLimitNotifier,
95: 	feature codygateway.Feature,
96: 	next http.Handler,
97: 	extractUsage func(responseHeaders http.Header) (int, error),
98: ) http.Handler {
99: 	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
100: 		act := actor.FromContext(r.Context())
101: 		logger := act.Logger(sgtrace.Logger(r.Context(), baseLogger))
102: 
103: 		r = r.WithContext(context.WithValue(r.Context(), ContextKeyFeature, feature))
104: 
105: 		l, ok := act.Limiter(r.Context(), logger, cache, feature, rateLimitNotifier)
106: 		if !ok {
107: 			response.JSONError(logger, w, http.StatusForbidden, errors.Newf("no access to feature %s", feature))
108: 			return
109: 		}
110: 
111: 		commit, err := l.TryAcquire(r.Context())
112: 		if err != nil {
113: 			limitedCause := "quota"
114: 			defer func() {
115: 				limitMap := map[string]any{}
116: 				var limitExceededError limiter.RateLimitExceededError
117: 				if errors.As(err, &limitExceededError) {
118: 					limitMap["limit"] = limitExceededError.Limit
119: 					limitMap["retry_after"] = limitExceededError.RetryAfter
120: 				}
121: 				if loggerErr := eventLogger.LogEvent(
122: 					r.Context(),
123: 					events.Event{
124: 						Name:       codygatewayevents.EventNameRateLimited,
125: 						Source:     act.Source.Name(),
126: 						Identifier: act.ID,
127: 						Metadata: events.MergeMaps(limitMap, map[string]any{
128: 							"error": err.Error(),
129: 							codygatewayevents.CompletionsEventFeatureMetadataField: feature,
130: 							"cause": limitedCause,
131: 
132: 							// Sourcegraph metadata
133: 							"sg_actor_id":            r.Header.Get("X-Sourcegraph-Actor-UID"),
134: 							"sg_actor_anonymous_uid": r.Header.Get("X-Sourcegraph-Actor-Anonymous-UID"),
135: 						}),
136: 					},
137: 				); loggerErr != nil {
138: 					logger.Error("failed to log event", log.Error(loggerErr))
139: 				}
140: 			}()
141: 
142: 			var rateLimitExceeded limiter.RateLimitExceededError
143: 			if errors.As(err, &rateLimitExceeded) {
144: 				rateLimitExceeded.WriteResponse(w)
145: 				return
146: 			}
147: 
148: 			if errors.Is(err, limiter.NoAccessError{}) {
149: 				response.JSONError(logger, w, http.StatusForbidden, err)
150: 				return
151: 			}
152: 
153: 			response.JSONError(logger, w, http.StatusInternalServerError, err)
154: 			return
155: 		}
156: 
157: 		responseRecorder := httpresponsewriter.NewStatusHeaderRecorder(w, logger)
158: 		next.ServeHTTP(responseRecorder, r)
159: 
160: 		// If response is healthy, consume the rate limit
161: 		if responseRecorder.StatusCode >= 200 && responseRecorder.StatusCode < 300 {
162: 			usage, err := extractUsage(w.Header())
163: 			if err != nil {
164: 				logger.Error("failed to extract usage", log.Error(err))
165: 			}
166: 			if err := commit(r.Context(), usage); err != nil {
167: 				logger.Error("failed to commit rate limit consumption", log.Error(err))
168: 			}
169: 		}
170: 	})
171: }
172: 
173: // ListLimitsHandler returns a map of all features and their current rate limit usages.
174: func ListLimitsHandler(baseLogger log.Logger, redisStore limiter.RedisStore) http.Handler {
175: 	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
176: 		act := actor.FromContext(r.Context())
177: 		logger := act.Logger(sgtrace.Logger(r.Context(), baseLogger))
178: 
179: 		res := map[codygateway.Feature]listLimitElement{}
180: 
181: 		// Iterate over all features.
182: 		for _, f := range codygateway.AllFeatures {
183: 			// Get the limiter, but don't log any rate limit events, the only limits enforced
184: 			// here are concurrency limits, and we should not care about those.
185: 			l, ok := act.Limiter(r.Context(), logger, redisStore, f, noopRateLimitNotifier)
186: 			if !ok {
187: 				response.JSONError(logger, w, http.StatusForbidden, errors.Newf("no access to feature %s", f))
188: 				return
189: 			}
190: 
191: 			// Capture the current usage.
192: 			currentUsage, expiry, err := l.Usage(r.Context())
193: 			if err != nil {
194: 				if errors.HasType[limiter.NoAccessError](err) {
195: 					// No access to this feature, skip.
196: 					continue
197: 				}
198: 				response.JSONError(logger, w, http.StatusInternalServerError, errors.Wrapf(err, "failed to get usage for %s", f))
199: 				return
200: 			}
201: 
202: 			// Find the configured rate limit. This should always be set after reading the Usage,
203: 			// but just to be safe, we add an existence check here.
204: 			rateLimit, ok := act.RateLimits[f]
205: 			if !ok {
206: 				response.JSONError(logger, w, http.StatusInternalServerError, errors.Newf("rate limit for %q not found", string(f)))
207: 				return
208: 			}
209: 
210: 			el := listLimitElement{
211: 				Limit:    rateLimit.Limit,
212: 				Interval: rateLimit.Interval.String(),
213: 				Usage:    int64(currentUsage),
214: 			}
215: 			if !expiry.IsZero() {
216: 				el.Expiry = &expiry
217: 			}
218: 			res[f] = el
219: 		}
220: 
221: 		w.Header().Add("Content-Type", "application/json")
222: 		if err := json.NewEncoder(w).Encode(res); err != nil {
223: 			baseLogger.Debug("failed to marshal json response", log.Error(err))
224: 		}
225: 	})
226: }
227: 
228: func RefreshLimitsHandler(baseLogger log.Logger) http.Handler {
229: 	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
230: 		act := actor.FromContext(r.Context())
231: 
232: 		if err := act.Update(r.Context()); err != nil {
233: 			logger := act.Logger(trace.Logger(r.Context(), baseLogger))
234: 			if actor.IsErrActorRecentlyUpdated(err) {
235: 				response.JSONError(logger, w, http.StatusTooManyRequests, err)
236: 			} else {
237: 				response.JSONError(logger, w, http.StatusInternalServerError, err)
238: 			}
239: 			return
240: 		}
241: 
242: 		w.WriteHeader(http.StatusOK)
243: 	})
244: }
245: 
246: type listLimitElement struct {
247: 	Limit    int64      `json:"limit"`
248: 	Interval string     `json:"interval"`
249: 	Usage    int64      `json:"usage"`
250: 	Expiry   *time.Time `json:"expiry,omitempty"`
251: }
252: 
253: func noopRateLimitNotifier(_ context.Context, _ notify.CodyGatewayActor, _ codygateway.Feature, _ float32, _ time.Duration) {
254: 	// nothing
255: }
